package main


import (
  "fmt"
  "strings"
  "net/http"
  "io"
)


func main() {


  url := "https://192.168.0.1/proxy/network/integration/v1/sites/{siteId}/firewall/policies/ordering?sourceFirewallZoneId={sourceFirewallZoneId}&destinationFirewallZoneId={destinationFirewallZoneId}"
  method := "PUT"


  payload := strings.NewReader(`{
  "orderedFirewallPolicyIds": {
    "beforeSystemDefined": [
      "string"
    ],
    "afterSystemDefined": [
      "string"
    ]
  }
}`)


  client := &http.Client {
  }
  req, err := http.NewRequest(method, url, payload)


  if err != nil {
    fmt.Println(err)
    return
  }
  req.Header.Add("Accept", "application/json")
  req.Header.Add("X-API-Key", "<X-API-Key>")
  req.Header.Add("Content-Type", "application/json")


  res, err := client.Do(req)
  if err != nil {
    fmt.Println(err)
    return
  }
  defer res.Body.Close()


  body, err := io.ReadAll(res.Body)
  if err != nil {
    fmt.Println(err)
    return
  }
  fmt.Println(string(body))
}

