import http.client
import json


conn = http.client.HTTPSConnection("192.168.0.1")
payload = json.dumps({
  "orderedFirewallPolicyIds": {
    "beforeSystemDefined": [
      "string"
    ],
    "afterSystemDefined": [
      "string"
    ]
  }
})
headers = {
  'Accept': 'application/json',
  'X-API-Key': '<X-API-Key>',
  'Content-Type': 'application/json'
}
conn.request("PUT", "/proxy/network/integration/v1/sites/{siteId}/firewall/policies/ordering?sourceFirewallZoneId=%7BsourceFirewallZoneId%7D&destinationFirewallZoneId=%7BdestinationFirewallZoneId%7D", payload, headers)
res = conn.getresponse()
data = res.read()
print(data.decode("utf-8"))

